(function () {
  // ---------------------------------------------------------------
  // Publication data
  // type must be one of: "journal", "conference", "book", "editorship", "workshop"
  // pdf: path to a PDF placed in this repo's /files/ folder (or a full URL), or null
  // bibtex / abstract: fill in / replace with exact records as you go
  // year: null is used for entries without a confirmed publication year
  // ---------------------------------------------------------------
  var PUBS = [
    { year: 2026, type: "workshop", authors: "Lydia Blümel, Kai Sauerwald, Kenneth Skiba, Matthias Thimm", title: "On the Complexity of the Discussion-based Semantics in Abstraction Argumentation", venue: "24th International Workshop on Nonmonotonic Reasoning", pdf: "/files/nmr2026_LBKSKSTM.pdf", note: "Winner of best paper award" , bibtex: "@article{nmr2026_LBKSKSTM,\n  author  = {Bl\\\"umel, Lydia and Sauerwald, Kai and Skiba, Kenneth and Thimm, Matthias},\n  title   = {On the Complexity of the Discussion-based Semantics in Abstract Argumentation},\n  journal = {arXiv preprint arXiv:2604.11480},\n  year    = {2026}\n}", abstract: "We show that deciding whether an argument a is stronger than an argument b with respect to the discussion-based semantics of Amgoud and Ben-Naim is decidable in polynomial time. At its core, this problem is about deciding whether, for two vertices in a graph, the number of walks of each length ending in those vertices is the same. We employ results from automata theory and reduce this problem to the equivalence problem for semiring automata. This offers a new perspective on the computational complexity of ranking semantics, an area in which the complexity of many semantics remains open." },
    { year: 2026, type: "thesis", authors: "Kenneth Skiba", title: "Ranking Sets of Arguments in Abstract Argumentation", venue: "University of Hagen, Germany", pdf: "/files/phd_KS.pdf", bibtex: "@phdthesis{phd_KS,\n  author= {Kenneth Skiba}, \n  title = {Ranking Sets of Arguments in Abstract Argumentation},\n school = {University of Hagen, Germany},\n  year= {2026}}", abstract: "In this thesis, we explore various approaches to rank sets of arguments within an abstract argumentation framework, providing more nuanced reasoning that goes beyond traditional binary classification. These approaches allow us to determine not only whether sets of arguments are accepted but also whether one set is more “acceptable” than another. We introduce the notion of extension-ranking semantics, which creates a preorder over the powerset of arguments, enabling us to compare the plausibility of acceptance of different sets." },
    { year: 2025, type: "editorship", authors: "Carl Corea, Jérôme Delobelle, John Grant, Jean-Guy Mailly, Julien Rossit, Kenneth Skiba, (Eds.)", title: "Joint Proceedings of the ECSQARU 2025 Workshops and Tutorials", venue: "Joint Workshop and Tutorials co-located with ECSQARU 2025", pdf: null, bibtex: "@proceedings{CoreaDGMRS2025,\n  editor    = {Corea, Carl and Delobelle, J\\'er\\^ome and Grant, John and Mailly, Jean-Guy and Rossit, Julien and Skiba, Kenneth},\n  title     = {Joint Proceedings of the ECSQARU 2025 Workshops and Tutorials},\n  year      = {2025}\n}", abstract: null },
    { year: 2025, type: "workshop", authors: "Dominik Lewin, Kenneth Skiba", title: "On Uncertainty in Collective Attacks in Abstract Argumentation", venue: "Joint Proceedings of the ECSQARU 2025 Workshops and Tutorials", pdf: "/files/argu2025_DLKS.pdf", bibtex: "@inproceedings{argu2026_DLKS,\n  author    = {Lewin, Dominik and Skiba, Kenneth},\n  title     = {On Uncertainty in Collective Attacks in Abstract Argumentation},\n  booktitle = {Joint Proceedings of the ECSQARU 2025 Workshops and Tutorials},\n  year      = {2025}\n}", abstract:  "We introduce incomplete argumentation frameworks with set attacks (ISETAFs), a novel generalisation of abstract argumentation frameworks that integrates set-based attacks and incomplete information. This unified model subsumes both argumentation frameworks with set attacks (SETAFs) and incomplete argumentation frameworks (IAFs) and is designed to better capture uncertainty in real-world argumentative reasoning. We explore two complementary approaches: a completion-based semantics that evaluates all possible completions, and an extension-based semantics that defines new acceptance conditions directly over ISETAFs. We show that key reasoning problems for ISETAFs are no harder than for IAFs, and we analyse which desirable properties (e.g., I-maximality, conflict-sensitivity, directionality) are preserved. Our results demonstrate that ISETAFs maintain the expressiveness and semantic rigour of existing frameworks, while significantly enhancing their modelling capabilities." },
    { year: 2025, type: "conference", authors: "Kai Sauerwald, Kenneth Skiba, Eduardo Fermé, Thomas Meyer", title: "Axiomatics of Restricted Choices by Linear Orders of Sets with Minimum as Fallback", venue: "19th European Conference on Logics in Artificial Intelligence (JELIA 2025)", pdf: "/files/jelia2025_KSKSEFTM.pdf", bibtex: "@article{jelia2025_KSKSEFTM,\n  author  = {Sauerwald, Kai and Skiba, Kenneth and Ferm\\'e, Eduardo and Meyer, Thomas},\n  title   = {Axiomatics of Restricted Choices by Linear Orders of Sets with Minimum as Fallback},\n  booktitle={Logics in Artificial Intelligence},\n year={2026},\n publisher={Springer Nature Switzerland},\n pages={58--74}}", abstract: "We study how linear orders can be employed to realise choice functions for which the set of potential choices is restricted, i.e., the possible choice is not possible among the full powerset of all alternatives. In such restricted settings, constructing a choice function via a relation on the alternatives is not always possible. However, we show that one can always construct a choice function via a linear order on sets of alternatives, even when a fallback value is encoded as the minimal element in the linear order. The axiomatics of such choice functions are presented for the general case and the case of union-closed input restrictions. Restricted choice structures have applications in knowledge representation and reasoning, and here we discuss their applications for theory change and abstract argumentation." },
    { year: 2025, type: "conference", authors: "Lars Bengel, Giovanni Buraglio, Jan Maly, Kenneth Skiba", title: "An Extension-Based Argument-Ranking Semantics: Social Rankings in Abstract Argumentation", venue: "Proceedings of the AAAI Conference on Artificial Intelligence (AAAI 2025)", pdf: "/files/aaai2025_LBGBJMKS.pdf", bibtex: "@inproceedings{aaai2025_LBGBJMKS,\n  author    = {Bengel, Lars and Buraglio, Giovanni and Maly, Jan and Skiba, Kenneth},\n  title     = {An Extension-Based Argument-Ranking Semantics: Social Rankings in Abstract Argumentation},\n  booktitle = {Proceedings of the AAAI Conference on Artificial Intelligence},\n  year      = {2025}\n}", abstract: "In this paper, we introduce a new family of argument-ranking semantics which can be seen as a refinement of the classification of arguments into skeptically accepted, credulously accepted and rejected. To this end we use so-called social ranking functions which have been developed recently to rank individuals based on their performance in groups. We provide necessary and sufficient conditions for a social ranking function to give rise to an argument-ranking semantics satisfying the desired refinement property." },
    { year: 2024, type: "conference", authors: "Kenneth Skiba, Matthias Thimm, Johannes Wallner", title: "Ranking Transition-Based Medical Recommendations Using Assumption-Based Argumentation", venue: "Conference on Advances in Robust Argumentation Machines (RATIO 2024)", pdf:  "/files/ratio2024_KSMTJW.pdf", bibtex: "@inproceedings{ratio2024_KSMTJW,\n  author    = {Skiba, Kenneth and Thimm, Matthias and Wallner, Johannes},\n  title     = {Ranking Transition-Based Medical Recommendations Using Assumption-Based Argumentation},\n  booktitle = {Conference on Advances in Robust Argumentation Machines},\n  year      = {2024}\n}", abstract: "We present a general framework to rank assumption in assumption-based argumentation frameworks (ABA frameworks), relying on their relationship to other assumptions and the syntactical structure of the ABA framework. We propose a new family of semantics for ABA frameworks that is using reductions to the abstract argumentation setting and leveraging existing ranking-based semantics for abstract argumentation. We show the suitability of these semantics by investigating a case study based on medical recommendations for patients with multiple health conditions and show that the relationship of the recommendations are enough to establish a ranking between the recommendations." },
        { year: 2024, type: "workshop", authors: "Lars Bengel, Giovanni Buraglio, Jan Maly, Kenneth Skiba", title: "An Extension-Based Argument-Ranking Semantics: Social Rankings in Abstract Argumentation", venue: "Proceedings of the 22nd International Workshop on Nonmonotonic Reasoning (NMR 2024), co-located with KR 2024", pdf: "/files/nmr2024_LBGBJMKS.pdf", bibtex: "@inproceedings{nmr2024_LBGBJMKS,\n  author    = {Bengel, Lars and Buraglio, Giovanni and Maly, Jan and Skiba, Kenneth},\n  title     = {An Extension-Based Argument-Ranking Semantics: Social Rankings in Abstract Argumentation},\n  booktitle = {Proceedings of the 22nd International Workshop on Nonmonotonic Reasoning (NMR 2024)},\n  year      = {2024}\n}", abstract: "In this paper, we introduce a new family of argument-ranking semantics which can be seen as a refinement of the classification of arguments into skeptically accepted, credulously accepted and rejected. To this end we use so-called social ranking functions which have been developed recently to rank individuals based on their performance in groups. We provide necessary and sufficient conditions for a social ranking function to give rise to an argument-ranking semantics satisfying the desired refinement property." },
    { year: 2023, type: "editorship", authors: "Kenneth Skiba, Jesse Heyninck, Matthias Thimm, M. (Eds.)", title: "Special Issue: Argument Strength (ArgStrength-21)", venue: "Argument & Computation", pdf: null, bibtex: "@article{argstrength2021_KSJHMT,\n  author  = {Skiba, Kenneth and Heyninck, Jesse and Thimm, Matthias},\n  title   = {Special Issue: Argument Strength (ArgStrength-21)},\n  journal = {Argument \\& Computation},\n  year    = {2023}\n}", abstract: null },
    { year: 2023, type: "workshop", authors: "Kenneth Skiba", title: "Bridging the Gap between Ranking-based Semantics and Extension-ranking Semantics", venue: "9th Workshop on Formal and Cognitive Reasoning co-located with the 46th German Conference on Artificial Intelligence (KI 2023)", pdf: "/files/fcr2023_KS.pdf", bibtex: "@inproceedings{fcr2023_KS,\n  author    = {Skiba, Kenneth},\n  title     = {Bridging the Gap between Ranking-based Semantics and Extension-ranking Semantics},\n  booktitle = {Proceedings of the 9th Workshop on Formal and Cognitive Reasoning co-located with the 46th German Conference on Artificial Intelligence {(KI} 2023)},\n  year      = {2023}\n}", abstract: "In this paper, we discuss the relationship between ranking-based semantics and extension-ranking semantics in the area of abstract argumentation frameworks. In particular, we investigate approaches to transform these two semantics into each other, ie going from a ranking over arguments to a ranking over sets of arguments (lifting) and from a ranking over sets of arguments to a ranking over arguments (social ranking). Additionally, we analyse the principles and properties the resulting semantics do satisfy." },
    { year: 2023, type: "workshop", authors: "Kenneth Skiba, Matthias Thimm, Johannes Wallner", title: "Ranking-based Semantics for Assumption-based Argumentation", venue: "9th Workshop on Formal and Cognitive Reasoning co-located with the 46th German Conference on Artificial Intelligence (KI 2023)", pdf: "/files/fcr2023_KSMTJW.pdf", bibtex: "@inproceedings{fcr2023_KSMTJW,\n  author    = {Skiba, Kenneth and Thimm, Matthias and Wallner, Johannes},\n  title     = {Ranking-based Semantics for Assumption-based Argumentation},\n  booktitle = {Proceedings of the 9th Workshop on Formal and Cognitive Reasoning co-located with the 46th German Conference on Artificial Intelligence {(KI} 2023)}},\n  year      = {2023}\n}", abstract: "We present a general framework to rank assumptions in assumption-based argumentation frameworks (ABA frameworks), relying on their relationship to other assumptions and the syntactical structure of the ABA framework. We define general principles for assessing the suitability of ranking-based semantics and propose a new family of semantics for ABA frameworks that is using reductions to the abstract argumentation setting and leveraging existing ranking-based semantics for abstract argumentation. We show that this family complies with many of our principles." },
    { year: 2023, type: "journal", authors: "Jesse Heyninck, Gabriele Kern-Isberner, Tjitze Rienstra, Kenneth Skiba, Matthias Thimm", title: "Revision, defeasible conditionals and non-monotonic inference for abstract dialectical frameworks", venue: "Artificial Intelligence", pdf: "/files/AIJ2023_JHGKITRKSMT.pdf", bibtex: "@article{AIJ2023_JHGKITRKSMT,\n  author  = {Heyninck, Jesse and Kern-Isberner, Gabriele and Rienstra, Tjitze and Skiba, Kenneth and Thimm, Matthias},\n  title   = {Revision, defeasible conditionals and non-monotonic inference for abstract dialectical frameworks},\n  journal = {Artificial Intelligence},\n  year    = {2023}\n}", abstract: "For propositional beliefs, there are well-established connections between belief revision, defeasible conditionals, and nonmonotonic inference. In argumentative contexts, such connections have not yet been investigated. On the one hand, the exact relationship between formal argumentation and nonmonotonic inference relations is a research topic that keeps on eluding researchers despite recently intensified efforts, whereas argumentative revision has been studied in numerous works during recent years. In this paper, we show that relationships between belief revision, defeasible conditionals, and nonmonotonic inference similar to those in propositional logic hold in argumentative contexts as well. We first define revision operators for abstract dialectical frameworks, and use such revision operators to define dynamic conditionals by means of the Ramsey test. We show that such conditionals can be equivalently defined using a total preorder over three-valued interpretations, and study the inferential behaviour of the resulting conditional inference relations." },
    { year: 2022, type: "editorship", authors: "Matthias Thimm, Jürgen Landes, Kenneth Skiba (Eds.)", title: "Proceedings of the First International Conference on Foundations, Applications, and Theory of Inductive Logic (FATIL2022)", venue: "Proceedings of the First International Conference on Foundations, Applications, and Theory of Inductive Logic (FATIL 2022)", pdf: null, bibtex: "@proceedings{fatil2022_MTJLKS,\n  editor = {Thimm, Matthias and Landes, J\\\"urgen and Skiba, Kenneth},\n  title  = {Proceedings of the First International Conference on Foundations, Applications, and Theory of Inductive Logic (FATIL 2022)},\n Publisher = {Universit\"atsbibliothek Hagen},\n url = {https://ub-deposit.fernuni-hagen.de/receive/mir_mods_00001860}, \n  year   = {2022}\n}", abstract: null },
       { year: 2022, type: "workshop", authors: "Kenneth Skiba", title: "Towards Realisability of Rankings-based Semantics", venue: "Proceedings of the First International Conference on Foundations, Applications, and Theory of Inductive Logic (FATIL 2022)", pdf: "/files/fatil2022_KS.pdf", bibtex: "@inproceedings{fatil2022_KS,\n  author = {Skiba, Kenneth},\n  title  = {Towards Realisability of Rankings-based Semantics}, \n	booktitle = {Proceedings of the First International Conference on Foundations, Applications, and Theory of Inductive Logic (FATIL 2022)}, \n year = {2022} \n}", abstract: null },
    { year: 2022, type: "conference", authors: "Matthias Lohr, Kenneth Skiba, Marco Konersmann, Jan Jürjens, Steffen Staab", title: "Formalizing cost fairness for two-party exchange protocols using game theory and applications to blockchain", venue: "2022 IEEE International Conference on Blockchain and Cryptocurrency (ICBC)", pdf: "/files/ICBC2022_MLKSMKJJSS.pdf", bibtex: "@inproceedings{ICBC2022_MLKSMKJJSS,\n  author    = {Lohr, Michael and Skiba, Kenneth and Konersmann, Marco and J\\\"urjens, Jan and Staab, Steffen},\n  title     = {Formalizing cost fairness for two-party exchange protocols using game theory and applications to blockchain},\n  booktitle = {2022 IEEE International Conference on Blockchain and Cryptocurrency (ICBC)},\n  year      = {2022}\n}", abstract: "Existing fair exchange protocols usually neglect consideration of cost when assessing their fairness. However, in an environment with non-negligible transaction cost, e.g., public blockchains, high or unexpected transaction cost might be an obstacle for wide-spread adoption of fair exchange protocols in business applications. For example, as of 2021-12-17, the initialization of the FairSwap protocol on the Ethereum blockchain requires the selling party to pay a fee of approx. 349.20 USD per exchange. We address this issue by defining cost fairness, which can be used to assess two-party exchange protocols including implied transaction cost. We show that in an environment with non-negligible transaction cost where one party has to initialize the exchange protocol and the other party can leave the exchange at any time cost fairness cannot be achieved." },
    { year: 2022, type: "workshop", authors: "Kenneth Skiba, Matthias Thimm, Tjitze Rienstra, Jesse Heyninck, Gabriele Kern-Isberner", title: "Realisability of Ranking-based Semantics", venue: "Proceedings of the Fourth International Workshop on Systems and Algorithms for Formal Argumentation (SAFA 2022)", pdf: "/files/safa2022_KSMTTRJHGKI.pdf", bibtex: "@inproceedings{safa2022_KSMTTRJHGKI.pdf,\n author = {Kenneth Skiba and Matthias Thimm and Tjitze Rienstra and Jesse Heyninck and Gabriele Kern-Isberner}, \n 	title = {Realisability of Ranking-based Semantics}, \n	booktitle = {Proceedings of the Fourth International Workshop on Systems and Algorithms for Formal Argumentation (SAFA 2022)}, \n	year = {2022}}", abstract: "In this work, we discuss the realisability problem for ranking-based semantics in the area of abstract argumentation. So, for a given ranking and ranking-based semantics, we want to find an AF st the selected ranking-based semantics induces our ranking when applied to the AF. We show that this question can be answered trivially with yes for a number of ranking-based semantics, ie for every ranking we can find such an AF. In addition to the discussion about the realisability problem, we also introduce a new equivalence notion for argumentation frameworks. We call two AFs ranking equivalent if they have the same ranking for a ranking-based semantics." },
       { year: 2022, type: "workshop", authors: "Tjitze Rienstra, Jesse Heyninck, Gabriele Kern-Isberner, Kenneth Skiba, Matthias Thimm", title: "Explaining Argument Acceptance in ADFs", venue: "Proceedings of the First International Workshop on Argumentation for eXplainable AI (ArgXAI 2022)", pdf: "/files/argxai2022_TRJHGKIKSMT.pdf", bibtex: "@inproceedings{argxai2022_TRJHGKIKSMT,\n  author = {Rienstra, Tjitze and Heyninck, Jesse and Kern-Isberner, Gabriele and Skiba, Kenneth and Thimm, Matthias},\n  title  = {Explaining Argument Acceptance in ADFs},\n, booktitle = {Proceedings of the First International Workshop on Argumentation for eXplainable AI (ArgXAI'22)}, \n  year   = {2021}\n}", abstract: "We present a dialogical proof theory for credulous acceptance in abstract dialectical frameworks under the preferred semantics. Our approach is motivated by the need to explain why an argument is accepted. The proof theory defines a set of rules for a dialogue between a proponent and opponent exchanging propositional formulas. The proponent takes on the role of trying to prove that the argument in question is acceptable, and the opponent takes on the role of exhaustively challenges the proponent’s moves, with a dialogue where the proponent wins represents a proof that the argument in question is accepted." },
      { year: 2022, type: "conference", authors: "Kenneth Skiba, Matthias Thimm", title: "Ordinal conditional functions for abstract argumentation", venue: "Proceedings of the 9th International Conference on Computational Models of Argument (COMMA 2022)", pdf: "/files/comma2022_KSMT.pdf", bibtex: "@inproceedings{comma2022_KSMT,\n  author    = {Skiba, Kenneth and Thimm, Matthias},\n  title     = {Ordinal conditional functions for abstract argumentation},\n  booktitle = {Proceedings of the 9th International Conference on Computational Models of Argument (COMMA 2022)},\n  year      = {2022}\n}", abstract: " We interpret and formalise ordinal conditional functions (OCFs) in abstract argumentation frameworks based on ideas and concepts defined for conditional logics. There, these functions are used to rank interpretations, and we adapt them to rank extensions instead. Using conflict-freeness and admissibility as two essential principles to define the semantics of OCFs, we obtain a framework that allows to rank sets of arguments wrt. their plausibility. We analyse the properties of this framework in-depth, and in doing so we establish a formal bridge between the approaches of abstract argumentation and conditional logics."},
    { year: 2022, type: "conference", authors: "Jesse Heyninck, Matthias Thimm, Gabriele Kern-Isberner, Tjitze Rienstra, Kenneth Skiba", title: "Conditional Abstract Dialectical Frameworks", venue: "Proceedings of the AAAI Conference on Artificial Intelligence (AAAI 2022)", pdf: "/files/aaai2022_JHMTGKITRKS.pdf", bibtex: "@inproceedings{aaai2022_JHMTGKITRKS,\n  author    = {Heyninck, Jesse and Thimm, Matthias and Kern-Isberner, Gabriele and Rienstra, Tjitze and Skiba, Kenneth},\n  title     = {Conditional Abstract Dialectical Frameworks},\n  booktitle = {Proceedings of the AAAI Conference on Artificial Intelligence (AAAI 2022)},\n  year      = {2022}\n}", abstract: "Abstract dialectical frameworks (in short, ADFs) are a unifying model of formal argumentation, where argumentative relations between arguments are represented by assigning acceptance conditions to atomic arguments. This idea is generalized by letting acceptance conditions being assigned to complex formulas, resulting in conditional abstract dialectical frameworks (in short, cADFs). We define the semantics of cADFs in terms of a non-truth-functional four-valued logic, and study the semantics in-depth, by showing existence results and proving that all semantics are generalizations of the corresponding semantics for ADFs." },
        { year: 2021, type: "conference", authors: "Kenneth Skiba, Tjitze Rienstra, Matthias Thimm, Jesse Heyninck, Gabriele Kern-Isberner", title: "Ranking Extensions in Abstract Argumentation", venue: "Proceedings of the 30th International Joint Conference on Artificial Intelligence (IJCAI 2021)", pdf: "/files/ijcai2021_KSTRMTJHGKI.pdf", bibtex: "@inproceedings{ijcai2021_KSTRMTJHGKI,\n  author    = {Skiba, Kenneth and Rienstra, Tjitze and Thimm, Matthias and Heyninck, Jesse and Kern-Isberner, Gabriele},\n  title     = {Ranking Extensions in Abstract Argumentation},\n  booktitle = {	booktitle = {Proceedings of the 30th International Joint Conference on Artificial Intelligence (IJCAI 2021)},\n  year      = {2021}\n}", abstract: "Extension-based semantics in abstract argumentation provide a criterion to determine whether a set of arguments is acceptable or not. In this paper, we present the notion of extension-ranking semantics, which determines a preordering over sets of arguments, where one set is deemed more plausible than another if it is somehow more acceptable. We obtain extension-based semantics as a special case of this new approach, but it also allows us to make more fine-grained distinctions, such as one set being “more complete” or “more admissible” than another. We define a number of general principles to classify extension-ranking semantics and develop concrete approaches. We also study the relation between extension-ranking semantics and argument-ranking semantics, which rank individual arguments instead of sets of arguments." },
    { year: 2021, type: "journal", authors: "Jesse Heyninck, Gabriele Kern-Isberner, Matthias Thimm, Kenneth Skiba", title: "On the correspondence between abstract dialectical frameworks and nonmonotonic conditional logics", venue: "Annals of Mathematics and Artificial Intelligence", pdf:  "/files/aomai2021_JHGKIMTKS.pdf", bibtex: "@article{aomai2021_JHGKIMTKS,\n  author  = {Heyninck, Jesse and Kern-Isberner, Gabriele and Thimm, Matthias and Skiba, Kenneth},\n  title   = {On the correspondence between abstract dialectical frameworks and nonmonotonic conditional logics},\n  journal = {Annals of Mathematics and Artificial Intelligence},\n  year    = {2021}\n}", abstract: "The exact relationship between formal argumentation and nonmonotonic logics is a research topic that keeps on eluding researchers despite recent intensified efforts. We contribute to a deeper understanding of this relation by investigating characterizations of abstract dialectical frameworks in conditional logics for nonmonotonic reasoning. We first show that in general, there is a gap between argumentation and conditional semantics when applying several intuitive translations, but then prove that this gap can be closed when focusing on specific classes of translations." },
    { year: 2021, type: "workshop", authors: "Jesse Heyninck, Matthias Thimm, Gabriele Kern-Isberner, Tjitze Riesntra, Kenneth Skiba", title: "Arguing about Complex Formulas: Generalizing Abstract Dialectical Frameworks", venue: "Proceedings of the 19th International Workshop on Non-Monotonic Reasoning (NMR 2021)", pdf:  "/files/nmr2021_JHMTGKITRKS.pdf", bibtex: "@inproceedings{nmr2021_JHMTGKITRKS,\n  author = {Heyninck, Jesse and Thimm, Matthias and Kern-Isberner, Gabriele and Rienstra, Tjitze and Skiba, Kenneth},\n  title  = {Arguing about Complex Formulas: Generalizing Abstract Dialectical Frameworks},\n 	booktitle = {Proceedings of the 19th International Workshop on Non-Monotonic Reasoning (NMR 2021)},\n year   = {2021}\n}", abstract: "Abstract dialectical frameworks (in short, ADFs) are a unifying model of formal argumentation, where argumentative relations between arguments are represented by assigning acceptance conditions to atomic arguments. This idea is generalized by letting acceptance conditions being assigned to complex formulas, resulting in conditional abstract dialectical frameworks (in short, cADFs). We define the semantics of cADFs in terms of a non-truth-functional four-valued logic, and study the semantics in-depth, by showing existence results and proving that all semantics are generalizations of the corresponding semantics for ADFs." },
    { year: 2021, type: "workshop", authors: "Jesse Heyninck, Matthias Thimm, Gabriele Kern-Isberner, Tjitze Rienstra, Kenneth Skiba", title: "On the Relation between Possibilistic Logic and Abstract Dialectical Frameworks", venue: "Proceedings of the 19th International Workshop on Non-Monotonic Reasoning (NMR 2021)", pdf: "/files/nmr2021_JHMTGKITRKS_b.pdf", bibtex: "@inproceedings{HeyninckTKRS2021c,\n  author = {Heyninck, Jesse and Thimm, Matthias and Kern-Isberner, Gabriele and Rienstra, Tjitze and Skiba, Kenneth},\n  title  = {On the Relation between Possibilistic Logic and Abstract Dialectical Frameworks},\n booktitle = {Proceedings of the 19th International Workshop on Non-Monotonic Reasoning (NMR 2021)},\n  year   = {2021}\n}", abstract: "Abstract dialectical frameworks (in short, ADFs) are one of the most general and unifying approaches to formal argumentation. As the semantics of ADFs are based on three-valued interpretations, the question poses itself as to whether some and which monotonic three-valued logic underlies ADFs, in the sense that it allows to capture the main semantic concepts underlying ADFs. As an entry-point for such an investigation, we take the concept of model of an ADF, which was originally formulated on the basis of Kleene’s threevalued logic. We show that an optimal concept of a model arises when instead of Kleene’s three-valued logic, possibilistic logic is used. We then show that in fact, possibilistic logic is the most conservative three-valued logic that fulfils this property, and that possibilistic logic can faithfully encode all other semantical concepts for ADFs. Based on this result, we also make some observations on strong equivalence and introduce possibilistic ADFs." },
    { year: 2021, type: "conference", authors: "Isabelle Kuhlmann, Tjitze Rienstra, Lars Bengel, Kenneth Skiba, Matthias Thimm", title: "Distinguishability in Abstract Argumentation", venue: "Proceedings of the International Conference on Principles of Knowledge Representation and Reasoning (KR 2021)", pdf:  "/files/kr2021_IKTRLBKSMT.pdf", bibtex: "@inproceedings{kr2021_IKTRLBKSMT,\n  author    = {Kuhlmann, Isabelle and Rienstra, Tjitze and Bengel, Lars and Skiba, Kenneth and Thimm, Matthias},\n  title     = {Distinguishability in Abstract Argumentation},\n  booktitle = {Proceedings of the International Conference on Principles of Knowledge Representation and Reasoning (KR 2021)},\n  year      = {2021}\n}", abstract: "n abstract argumentation, the admissible semantics can be said to distinguish the preferred semantics in the sense that argumentation frameworks with the same admissible extensions also have the same preferred extensions. In this paper we present an exhaustive study of such distinguishability relationships, including those between sets of semantics. We further examine restricted classes of argumentation frameworks, such as self-attack-free and acyclic frameworks. We discuss the relevance of our results in the context of the argumentation framework elicitation problem." },
        { year: 2021, type: "conference", authors: "Daniel Neugebauer, Jörg Rothe, Kenneth Skiba", title: "Complexity of nonemptiness in control argumentation frameworks", venue: "European Conference on Symbolic and Quantitative Approaches with Uncertainty (ECSQARU 2021)", pdf: "/files/ecsqaru2021_DNJRKS.pdf", bibtex: "@inproceedings{ecsqaru2021_DNJRKS,\n  author    = {Neugebauer, Daniel and Rothe, J\\\"org and Skiba, Kenneth},\n  title     = {Complexity of nonemptiness in control argumentation frameworks},\n  booktitle = {European Conference on Symbolic and Quantitative Approaches with Uncertainty (ECSQARU 2021) },\n  year      = {2021}\n}", abstract: "Control argumentation frameworks (CAFs)   extend the standard model of argumentation framework (AF) due to Dung  in a way that takes unquantified uncertainty regarding arguments and attacks into account. Complementing recent work by Skiba et al.  for incomplete argumentation frameworks, we study the (nonempty) existence problem for CAFs and fully analyze its computational complexity for the most common semantics." },
    { year: 2021, type: "journal", authors: "Kenneth Skiba, Daniel Neugebauer, Jörg Rothe", title: "Complexity of Nonempty Existence Problems in Incomplete Argumentation Frameworks", venue: "IEEE Intelligent Systems", pdf: "/files/IEEEIS2021_KSDNJR.pdf", bibtex: "@article{IEEEIS2021_KSDNJR,\n  author  = {Skiba, Kenneth and Neugebauer, Dorothea and Rothe, J\\\"org},\n  title   = {Complexity of Nonempty Existence Problems in Incomplete Argumentation Frameworks},\n  journal = {IEEE Intelligent Systems},\n  year    = {2020}\n}", abstract: "Abstract argumentation frameworks (AFs) are a prevailing model for the formal representation of argumentations in AI research. The generalized model of incomplete AFs extends the basic model by allowing for the representation of unquantified uncertainty about the existence of elements in an argumentation. For this extended model of AFs, we formally define a natural generalization of the nonempty existence problem, which asks whether there exists a nonempty set of arguments satisfying the conditions specified by a given semantics. Focusing on the fundamental semantics for incomplete AFs and considering a possible and a necessary variant of the nonempty existence problem, this yields a family of related problems, and we provide a full analysis of their computational complexity." },
    { year: 2020, type: "workshop", authors: "Kenneth Skiba", title: "Towards ordering sets of arguments", venue: "Processdings of Summer School on Argumentation (SSA 2020)", pdf: "/files/ssa2020_KS.pdf", bibtex: "@inproceedings{ssa2020_KS,\n  author    = {Skiba, Kenneth},\n  title     = {Towards ordering sets of arguments},\n  booktitle = {Proceedings of Summer School on Argumentation SSA2020},\n  year      = {2020}\n}", abstract: "Formal argumentation describes a family of approaches to modeling rational decision-making through the representation of arguments and their relationships. A particular important approach is that of abstract argumentation [4], which focuses on the representation of arguments and a conflict relation between arguments through modeling this setting as a directed graph. Here, arguments are identified by vertices and an attack from one argument to another is represented as a directed edge. This simple model already provides an interesting object of study, see [3] for an overview. Reasoning is usually performed in abstract argumentation by considering sets of arguments, ie, sets of arguments that are jointly acceptable given some formal account of “acceptability”. Therefore, this classical approach differentiates between “acceptable” arguments and “rejected” arguments. In this paper, we take a more general perspective on this issue by considering orders—ie, partial orders in the most general setting—over sets of arguments. So we want to compare different extensions based on their acceptability and then calculate an order accordingly to this comparison." },
    { year: 2020, type: "workshop", authors: "Kenneth Skiba", title: "A First Idea for a Ranking-Based Semantics using System Z", venue: "Online Handbook of Argumentation for AI (OHAAI 2020)", pdf: "/files/ohaai2020_KS.pdf", bibtex: "@incollection{ohaai2020_KS,\n  author    = {Skiba, Kenneth},\n  title     = {A First Idea for a Ranking-Based Semantics using System Z},\n  booktitle = {Online Handbook of Argumentation for AI (OHAAI 2020)},\n  year      = {2020}\n}", abstract: "We discuss ranking arguments from an Dung-style argumentation framework with the help of conditional logics. Using an intuitive translation for an argumentation framework to generate conditionals, we can apply nonmonotonic inference systems to generate a ranking on these conditionals. With this ranking we construct a ranking for our arguments." },
    { year: 2020, type: "workshop", authors: "Jesse Heyninck, Gabriele Kern-Isberner, Kenneth Skiba, Matthias Thimm", title: "Interpreting Conditionals in Argumentative Environments", venue: "Proceedings of the 18th International Workshop on Non-Monotonic Reasoning (NMR 2020)", pdf: "/files/nmr2020_JHGKIKSMT.pdf", bibtex: "@inproceedings{nmr2020_JHGKIKSMT,\n  author = {Heyninck, Jesse and Kern-Isberner, Gabriele and Skiba, Kenneth and Thimm, Matthias},\n  title  = {Interpreting Conditionals in Argumentative Environments},\n  Booktitle = {Proceedings of the 18th International Workshop on Non-Monotonic Reasoning (NMR 2020)}, \n year   = {2019}\n}", abstract: "In the field of knowledge representation and reasoning, different paradigms have co-existed for many years. Two central such paradigms are conditional logics and formal argumentation. Despite recent intensified efforts, the gap between these two approaches has not been fully bridged yet. In this paper, we contribute to the bridging of this gap by showing how plausible conditionals can be interpreted in argumentative reasoning enviroments. In more detail, we provide interpretations of conditional knowledge bases in abstract dialectical frameworks, one of the most general approaches to computational models of argumentation. We motivate the design choices made in our translation, show that different semantics give rise to several forms of adequacy, and show several desirable properties of our translation." },
       { year: 2020, type: "conference", authors: "Kenneth Skiba, Matthias Thimm, Andrea Cohen, Sebastian Gottifredi, Alejandro J García", title: "Abstract Argumentation Frameworks with Fallible Evidence", venue: "Proceedings of the 8th International Conference on Computational Models of Argument (COMMA 2020)", pdf:  "/files/comma2020_KSMTACSGAJG.pdf", bibtex: "@inproceedings{comma2020_KSMTACSGAJG,\n  author    = {Skiba, Kenneth and Thimm, Matthias and Cohen, Andrea and Gottifredi, Sebasti\\'an and Garc\\'ia, Alejandro},\n  title     = {Abstract Argumentation Frameworks with Fallible Evidence},\n  booktitle = {Proceedings of the 8th International Conference on Computational Models of Argument (COMMA 2020)},\n  year      = {2020}\n}", abstract: "We consider a generalisation of abstract argumentation frameworks where arguments need to be backed by pieces of evidence in order to be actually present in the argumentation framework. These pieces of evidence come with an associated cost for retrieval and may not be available at any given time. We model an information-seeking agent in this scenario that aims at deciding whether a certain argument is acceptable while minimising the total evidence retrieval cost. We investigate the computational complexity of decision variants of this optimisation problem and find that, depending on the underlying classical argumentation semantics, complexity rises one level in the polynomial hierarchy compared to the classical case." },
    { year: 2025, type: "book", authors: "Jesse Heyninck, Gabriele Kern-Isberner, Tjitze Rienstra, Kenneth Skiba, Matthias Thimm", title: "The semantical structure of conditionals, and its relation to formal argumentation", venue: "Handbook of Formal Argumentation (Volume 3)", pdf: "/files/hofa2025_JHGKITRKSMT.pdf", bibtex: "@incollection{hofa2025_JHGKITRKSMT,\n  author = {Jesse Heyninck and Gabriele Kern-Isberner and Tjitze Rienstra and Kenneth Skiba and Matthias Thimm},\n booktitle = {Handbook of Formal Argumentation (Volume 3)}, \n chapter = {8},\n	editor = {Dov Gabbay and Gabriele Kern-Isberner and Guillermo R. Simari and Matthias Thimm}, \n	publisher = {College Publications}, \n title = {The semantical structure of conditionals, and its relation to formal argumentation},\n 	volume = {3}, \n year = {2024}}}", abstract: "Conditionals, ie expressions of the logical form “if A, then B”, have been a central topic of study ever since logic was on the academic menu. In contemporary logic, there is a consensus that the semantics of conditionals are best obtained by stipulating a subset of possible worlds in which the antecedent is true, and verifying whether the consequent is true in those worlds. Such a subset of possible worlds can represent, for example, the most typical worlds in which the antecedent is true. This idea has proven a fruitful basis, allowing for many systematic characterisation results as well as for making connections to other topics, such as belief revision and modal logic. In formal argumentation, the potential of these semantical ideas has not gone unnoticed in the last years, and many works have attempted to bridge the worlds of conditionals and arguments on the basis of these ideas. In this article, we give a thorough introduction to the semantics of conditionals and survey the adaptions of these semantics in the literature on computational argumentation, including structured argumentation and generalisations of abstract argumentation such as abstract dialectical frameworks. Furthermore, we highlight opportunities for future research on this topic." },
    { year: 2024, type: "conference", authors: "Kenneth Skiba, Matthias Thimm", title: "Optimisation and Approximation in Abstract Argumentation: The Case of Admissibility", venue: "Proceedings of the 21st International Conference on Principles of Knowledge Representation and Reasoning (KR 2024)", pdf: "/files/kr2024_KSMT.pdf", bibtex: "@inproceedings{kr2024_KSMT,\n  author = {Kenneth Skiba and Matthias Thimm}, \n	booktitle = {Proceedings of the 21st International Conference on Principles of Knowledge Representation and Reasoning (KR 2024)},\n	title = {Optimisation and Approximation in Abstract Argumentation: The Case of Admissibility}, \n	year = {2024}}", abstract: "We propose two soft notions of the notion of admissibility in abstract argumentation. The first one weakens the defence notion by allowing, to a certain degree, undefended attacks, and the second one allows, to a certain degree, conflicts within sets of arguments. We analyse these new semantical notions based on the computational complexity of optimisation and approximation. Finally, we discuss and analyse soft notions for preferred semantics." },
    { year: 2022, type: "conference", authors: "Jesse Heyninck, Gabriele Kern-Isberner, Tjitze Rienstra, Kenneth Skiba, Matthias Thimm", title: "Possibilistic Logic Underlies Abstract Dialectical Frameworks", venue: "Proceedings of the 31st International Joint Conference on Artificial Intelligence (IJCAI 2022)", pdf: "/files/ijcai2022_JHGKITRKSMT.pdf", bibtex: "@inproceedings{ijcai2022_JHGKITRKSMT,\n  author = {Heyninck, Jesse and Kern-Isberner, Gabriele and Rienstra, Tjitze and Skiba, Kenneth and Thimm, Matthias},\n  title  = {Possibilistic Logic Underlies Abstract Dialectical Frameworks}, \n booktitle = {Proceedings of the 31st International Joint Conference on Artificial Intelligence (IJCAI 2022)},\n 	year = {2022}}", abstract: "Abstract dialectical frameworks (in short, ADFs) are one of the most general and unifying approaches to formal argumentation. As the semantics of ADFs are based on three-valued interpretations, we ask which monotonic three-valued logic allows to capture the main semantic concepts underlying ADFs. We show that possibilistic logic is the unique logic that can faithfully encode all other semantical concepts for ADFs. Based on this result, we also characterise strong equivalence and introduce possibilistic ADFs." },
    { year: 2021, type: "workshop", authors: "Kenneth Skiba", title: "Towards Ranking Arguments in Incomplete Argumentation Frameworks", venue: "Proceedings of the Third Workshop on Argument Strength (ArgStrength 2021)", pdf: "/files/argstrength2021_KS.pdf", bibtex: "@inproceedings{argstrength2021_KS,\n  author = {Skiba, Kenneth},\n  title  = {Towards Ranking Arguments in Incomplete Argumentation Frameworks}\n, booktitle= {Proceedings of the Third Workshop on Argument Strength (ArgStrength 2021)}, \n year= {2021}}", abstract: null },
    { year: 2021, type: "conference", authors: "Jesse Heyninck, Gabriele Kern-Isberner, Tjitze Rienstra, Kenneth Skiba, Matthias Thimm.", title: "Revision and Conditional Inference for Abstract Dialectical Frameworks", venue: "Proceedings of the 18th International Conference on Principles of Knowledge Representation and Reasoning (KR 2021)", pdf: "/files/kr2021_JHGKITRKSMT.pdf", bibtex: "@inproceedings{kr2021_JHGKITRKSMT,\n  author = {Heyninck, Jesse and Kern-Isberner, Gabriele and Rienstra, Tjitze and Skiba, Kenneth and Thimm, Matthias},\n  title  = {Revision and Conditional Inference for Abstract Dialectical Frameworks}, \n booktitle = {Proceedings of the 18th International Conference on Principles of Knowledge Representation and Reasoning (KR 2021)}, year = {2021} \n }", abstract: "For propositional beliefs, there are well-established connections between belief revision, defeasible conditionals and nonmonotonic inference. In argumentative contexts, such connections have not yet been investigated. On the one hand, the exact relationship between formal argumentation and nonmonotonic inference relations is a research topic that keeps on eluding researchers despite recently intensified efforts, whereas argumentative revision has been studied in numerous works during recent years. In this paper, we show that similar relationships between belief revision, defeasible conditionals and nonmonotonic inference hold in argumentative contexts as well. We first define revision operators for abstract dialectical frameworks, and use such revision operators to define dynamic conditionals by means of the Ramsey test. We show that such conditionals can be equivalently defined using a total preorder over three-valued interpretations, and study the inferential behaviour of the resulting conditional inference relations." },
        { year: 2020, type: "workshop", authors: "Kenneth Skiba", title: "Towards a Ranking-Based Semantics using System Z", venue: "1st Doctoral Consortium at the European Conference on Artificial Intelligence (DC-ECAI 2020)", pdf: "/files/ecaiddc2020_ks.pdf", bibtex: "@inproceedings{ecaiddc2020_ks,\n  author    = {Skiba, Kenneth},\n  title     = {Towards a Ranking-Based Semantics using System Z},\n  booktitle = {1st Doctoral Consortium at ECAI (DC-ECAI 2020)},\n  year      = {2020}\n}", abstract: "We discuss ranking arguments from an Dung-style argumentation framework with the help of conditional logics. Using an intuitive translation for an argumentation framework to generate conditionals, we can apply nonmonotonic inference systems to generate a ranking on these conditionals. With this ranking we construct a ranking for our arguments." },
    { year: 2020, type: "workshop", authors: "Kenneth Skiba, Matthias Thimm", title: "Towards Ranking-based Semantics for Abstract Argumentation using Conditional Logic Semantics", venue: "Proceedings of the International Workshop on Computational Argumentation and Cognition (COGNITAR 2020)", pdf: "/files/cognitar2020_KSMT.pdf", bibtex: "@article{cognitar2020_KSMT,\n  author  = {Skiba, Kenneth and Thimm, Matthias},\n  title   = {Towards Ranking-based Semantics for Abstract Argumentation using Conditional Logic Semantics},\n  Booktitle = {Proceedings of the International Workshop on Computational Argumentation and Cognition (COGNITAR 2020)},\n  year    = {2020}\n}", abstract: "We propose a novel ranking-based semantics for Dung-style argumentation frameworks with the help of conditional logics. Using an intuitive translation for an argumentation framework to generate conditionals, we can apply nonmonotonic inference systems to generate a ranking on possible worlds. With this ranking we construct a ranking for our arguments. With a small extension to this ranking-based semantics we already satisfy some desirable properties for a ranking over arguments." },
    { year: 2020, type: "conference", authors: "Kenneth Skiba, Daniel Neugebauer, Jörg Rothe", title: "Complexity of Possible and Necessary Existence Problems in Abstract Argumentation", venue: "Proceedings of the 24th European Conference on Artificial Intelligence (ECAI 2020)", pdf: "/files/ecai2020_KSDNJR.pdf", bibtex: "@inproceedings{ecai2020_KSDNJR,\n  author = {Skiba, Kenneth and Neugebauer, Daniel and Rothe, J\\\"org},\n  title  = {Complexity of Possible and Necessary Existence Problems in Abstract Argumentation},\n booktitle= {Proceedings of the 24th European Conference on Artificial Intelligence (ECAI 2020)}, \n year= {2020}}", abstract: "This work focuses on generalizing the existence problems for extensions in abstract argumentation to incomplete argumentation frameworks. In this extended model, incomplete or conflicting knowledge about the state of the arguments and attacks are allowed. We propose possible and necessary variations of the existence and nonemptiness problems, originally defined for (complete) argumentation frameworks, to extend these problems to incomplete argumentation frameworks. While the computational complexity of existence problems is already known for the standard model, we provide a full analysis of the complexity for incomplete argumentation frameworks using the most prominent semantics, namely, the conflict-free, admissible, complete, grounded, preferred, and stable semantics. We show that the complexity rises from NP-completeness to Πp." }
  ];

  var TYPE_LABEL = {
    journal: "Journal Paper",
    conference: "Conference Paper",
    workshop: "Workshop / Other",
    book: "Book",
    editorship: "Editorship",
    thesis: "Thesis"
  };

  function escapeHtml(str) {
    return String(str).replace(/[&<>"']/g, function (c) {
      return { "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[c];
    });
  }

  function renderEntry(pub) {
    var el = document.createElement("div");
    el.className = "pub-entry pub-" + pub.type;
    el.setAttribute("data-type", pub.type);

    var badge = '<span class="pub-badge pub-' + pub.type + '">' + TYPE_LABEL[pub.type] + '</span>';
    var title = '<div class="pub-title">' + badge + escapeHtml(pub.title) + '</div>';
    var authors = '<div class="pub-authors">' + escapeHtml(pub.authors) + '</div>';
    var venue = pub.venue ? '<div class="pub-venue">' + escapeHtml(pub.venue) + '</div>' : '';
    var note = pub.note ? '<div class="pub-note">' + escapeHtml(pub.note) + '</div>' : '';

    var links = '<div class="pub-links">';
    if (pub.pdf) {
      links += '<a class="pub-pdf" href="' + escapeHtml(pub.pdf) + '" target="_blank" rel="noopener">PDF</a>';
    }
    if (pub.abstract) {
      links += '<details class="pub-fold"><summary>Abstract</summary>' +
               '<div class="pub-fold-body pub-abstract-body">' + escapeHtml(pub.abstract) + '</div></details>';
    }
    if (pub.bibtex) {
      links += '<details class="pub-fold"><summary>BibTeX</summary>' +
               '<div class="pub-fold-body"><pre>' + escapeHtml(pub.bibtex) + '</pre></div></details>';
    }
    links += '</div>';

    el.innerHTML = title + authors + venue + note + links;
    return el;
  }

  function render(filter) {
    var list = document.getElementById("pub-list");
    list.innerHTML = "";

    var byYear = {};
    var years = [];
    PUBS.forEach(function (pub) {
      var y = pub.year === null ? "n.d." : pub.year;
      if (!byYear[y]) { byYear[y] = []; years.push(y); }
      byYear[y].push(pub);
    });

    years.sort(function (a, b) {
      if (a === "n.d.") return 1;
      if (b === "n.d.") return -1;
      return b - a;
    });

    var shown = 0;
    years.forEach(function (y) {
      var entries = byYear[y].filter(function (pub) {
        return filter === "all" || pub.type === filter;
      });
      if (entries.length === 0) return;

      var heading = document.createElement("div");
      heading.className = "pub-year-heading";
      heading.textContent = y;
      list.appendChild(heading);

      entries.forEach(function (pub) {
        list.appendChild(renderEntry(pub));
        shown++;
      });
    });

    if (shown === 0) {
      var empty = document.createElement("div");
      empty.className = "pub-empty";
      empty.textContent = "No publications in this category yet.";
      list.appendChild(empty);
    }
  }

  document.querySelectorAll(".pub-filter-btn").forEach(function (btn) {
    btn.addEventListener("click", function () {
      document.querySelectorAll(".pub-filter-btn").forEach(function (b) { b.classList.remove("active"); });
      btn.classList.add("active");
      render(btn.getAttribute("data-filter"));
    });
  });

  render("all");
})();
